{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { margin: 12mm 14mm 8mm 14mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 820px; margin: 0 auto; padding: 0; }

  .hotel-logo { max-height: 70px; max-width: 140px; }
  .logo-box {
    display: inline-block; width: 46px; height: 46px;
    background: #1a1a2e; color: #fff; font-size: 16pt; font-weight: 700;
    text-align: center; line-height: 46px; border-radius: 5px;
  }
  .hotel-name { font-size: 14pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7.5pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 14px 0 16px; }

  .pill {
    display: inline-block; padding: 2px 9px; border-radius: 10px;
    font-size: 7pt; font-weight: 700; text-transform: uppercase;
    letter-spacing: 0.4px; margin-right: 5px;
    border: 1px solid #d1d5db; background: #f9fafb; color: #374151;
  }
  .pills-row { margin-bottom: 14px; }

  .section-title {
    font-size: 7.5pt; font-weight: 700; color: #fff;
    text-transform: uppercase; letter-spacing: 0.6px;
    background: #1a1a2e; padding: 6px 9px;
    margin-top: 14px; margin-bottom: 8px;
  }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td {
    padding: 4px 8px; font-size: 9pt;
    border-bottom: 1px solid #f1f5f9;
    vertical-align: middle; white-space: nowrap;
  }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 22%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 28%; color: #1a1a2e; font-weight: 400; }

  .notes-box {
    border: 1px solid #e5e7eb; border-radius: 4px;
    padding: 8px 12px; font-size: 8.5pt; color: #374151; margin-bottom: 4px;
    line-height: 1.6;
  }

  .data-table { width: 100%; border-collapse: collapse; font-size: 8.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #1a1a2e; color: #fff; }
  .data-table thead th { padding: 6px 9px; text-align: left; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; }
  .data-table thead th.num { text-align: right; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 7px 9px; border-bottom: 1px solid #f1f5f9; color: #374151; }
  .data-table tbody td.num { text-align: right; }

  .check-row { display: inline-block; margin-right: 20px; font-size: 9pt; }
  .check-box { display: inline-block; width: 14px; height: 14px; border: 1.5px solid #1a1a2e; border-radius: 2px; margin-right: 5px; text-align: center; line-height: 13px; font-size: 10pt; vertical-align: middle; }
  .check-box.checked { background: #1a1a2e; color: #fff; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 20px 0 12px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 16px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Maintenance Task</div>
        <div class="doc-subtitle">Work Order</div>
        <div class="doc-ref">
          <strong>Task:</strong> {{ task.name }}<br>
          <strong>Generated:</strong> {{ generated_at }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- STATUS PILLS -->
  <div class="pills-row">
    {% set st = (task.status or '') | lower %}
    {% if st == 'completed' %}<span class="pill">&#10003; Completed</span>
    {% elif st == 'in progress' %}<span class="pill">&#9679; In Progress</span>
    {% elif st == 'open' %}<span class="pill">&#9679; Open</span>
    {% elif st == 'cancelled' %}<span class="pill">&#10007; Cancelled</span>
    {% else %}<span class="pill">{{ task.status }}</span>{% endif %}
    {% if task.priority %}<span class="pill">{{ task.priority }} Priority</span>{% endif %}
    {% if task.task_type %}<span class="pill">{{ task.task_type }}</span>{% endif %}
  </div>

  <!-- ORIGINATING REQUEST -->
  {% if task.maintenance_request %}
  <div class="section-title">Originating Request</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Request Ref</td>
      <td class="info-val">{{ task.maintenance_request }}</td>
      <td class="info-key">Issue Type</td>
      <td class="info-val">{{ task.issue_type or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Location</td>
      <td class="info-val">{{ task.location or '&mdash;' }}</td>
      <td class="info-key">Location Type</td>
      <td class="info-val">{{ task.request_location_type or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Reported By</td>
      <td class="info-val">{{ task.reported_by_name or task.reported_by or '&mdash;' }}</td>
      <td class="info-key">Department</td>
      <td class="info-val">{{ task.requesting_department_name or task.requesting_department or '&mdash;' }}</td>
    </tr>
    {% if task.asset_name or task.asset %}
    <tr>
      <td class="info-key">Asset</td>
      <td class="info-val" colspan="3">{{ task.asset_name or task.asset }}</td>
    </tr>
    {% endif %}
  </table>
  {% if task.request_title %}
  <div class="notes-box" style="margin-top:6px;">
    <div style="font-size:7pt;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#9ca3af;margin-bottom:4px;">Issue Description</div>
    {{ task.request_title }}
  </div>
  {% endif %}

  {% endif %}

  <!-- TASK DETAILS -->
  <div class="section-title">Task Details</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:22%" /><col style="width:28%" />
      <col style="width:22%" /><col style="width:28%" />
    </colgroup>
    <tr>
      <td class="info-key">Task Ref</td>
      <td class="info-val">{{ task.name }}</td>
      <td class="info-key">Status</td>
      <td class="info-val">{{ task.status or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Task Type</td>
      <td class="info-val">{{ task.task_type or '&mdash;' }}</td>
      <td class="info-key">Priority</td>
      <td class="info-val">{{ task.priority or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Technician</td>
      <td class="info-val">{{ task.technician_name or task.assigned_technician or '&mdash;' }}</td>
      <td class="info-key">Supervisor</td>
      <td class="info-val">{{ task.supervisor_name or task.supervisor or '&mdash;' }}</td>
    </tr>
    <tr>
      <td class="info-key">Start Time</td>
      <td class="info-val">{{ task.start_time or '&mdash;' }}</td>
      <td class="info-key">End Time</td>
      <td class="info-val">{{ task.end_time or '&mdash;' }}</td>
    </tr>
  </table>

  {% if task.task_description %}
  <div class="notes-box" style="margin-top:6px;">
    <div style="font-size:7pt;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#9ca3af;margin-bottom:4px;">Task Description</div>
    {{ task.task_description }}
  </div>
  {% endif %}

  <!-- WORK PERFORMED -->
  {% if task.work_performed or task.completion_notes %}
  <div class="section-title">Work Performed</div>
  {% if task.work_performed %}
  <div class="notes-box">
    <div style="font-size:7pt;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#9ca3af;margin-bottom:4px;">Work Done</div>
    {{ task.work_performed }}
  </div>
  {% endif %}
  {% if task.completion_notes %}
  <div class="notes-box" style="margin-top:6px;">
    <div style="font-size:7pt;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#9ca3af;margin-bottom:4px;">Completion Notes</div>
    {{ task.completion_notes }}
  </div>
  {% endif %}
  {% endif %}

  <!-- PARTS USED -->
  {% if task.parts_used %}
  <div class="section-title">Parts Used / Collected from Store</div>
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Item Code</th>
        <th>Item Name</th>
        <th class="num">Qty</th>
        <th>UOM</th>
        <th>Warehouse</th>
      </tr>
    </thead>
    <tbody>
      {% for p in task.parts_used %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;">{{ p.item_code }}</td>
        <td>{{ p.item_name or '&mdash;' }}</td>
        <td class="num">{{ p.qty }}</td>
        <td style="color:#6b7280;">{{ p.uom or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ p.warehouse or '&mdash;' }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <!-- PARTS RETURNED -->
  {% if task.parts_returned %}
  <div class="section-title">Parts Returned to Store</div>
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th>#</th>
        <th>Item Code</th>
        <th>Item Name</th>
        <th class="num">Qty</th>
        <th>UOM</th>
        <th>Warehouse</th>
      </tr>
    </thead>
    <tbody>
      {% for p in task.parts_returned %}
      <tr>
        <td style="color:#9ca3af;">{{ loop.index }}</td>
        <td style="font-weight:600;">{{ p.item_code }}</td>
        <td>{{ p.item_name or '&mdash;' }}</td>
        <td class="num">{{ p.qty }}</td>
        <td style="color:#6b7280;">{{ p.uom or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ p.warehouse or '&mdash;' }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <!-- COMPLETION CHECKLIST -->
  <div class="section-title">Completion Checklist</div>
  <table width="100%" cellpadding="0" cellspacing="0" style="padding:8px 0;">
    <tr>
      <td width="33%" style="padding:8px;">
        <span class="check-box {{ 'checked' if task.inspection_required else '' }}">{{ '&#10003;' if task.inspection_required else '&nbsp;' }}</span>
        &nbsp;Inspection Required
      </td>
      <td width="33%" style="padding:8px;">
        <span class="check-box {{ 'checked' if task.fault_diagnosed else '' }}">{{ '&#10003;' if task.fault_diagnosed else '&nbsp;' }}</span>
        &nbsp;Fault Diagnosed
      </td>
      <td width="33%" style="padding:8px;">
        <span class="check-box {{ 'checked' if task.test_run_passed else '' }}">{{ '&#10003;' if task.test_run_passed else '&nbsp;' }}</span>
        &nbsp;Test Run Passed
      </td>
    </tr>
  </table>

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This record is generated by the {{ company }} Property Management System.<br>
          <strong style="color:#374151;">Task: {{ task.name }} &nbsp;&middot;&nbsp; Generated: {{ generated_at }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
